code.C:
#include <stdio.h>
int gcd(int a, int b) { return b ? gcd(b, a % b) : a; }
int main() { int num, den; scanf("%d %d", &num, &den); int g = gcd(num, den); printf("%d/%d\n", num / g, den / g); return 0; }

