code.Java:
import java.util.Scanner;
public class Main { public static int gcd(int a, int b) { return b == 0 ? a : gcd(b, a % b); }
public static void main(String[] args) { Scanner sc = new Scanner(System.in); int num = sc.nextInt(); int den = sc.nextInt(); int g = gcd(num, den); System.out.println(num / g + "/" + den / g); } }

